	beforeEach(() => {
		usersRepository = new InMemoryUsersRepository()
		sut = new DeleteByIdService(usersRepository)

		usersRepository.users.push({
			id: '123',
			name: 'Admin',
			email: 'admin@admin.com',
			password: '123456',
			role: Role.ADMIN,
			createdAt: new Date(),
